import React from 'react';
import { Link } from 'react-router-dom';

const CategoryGrid = ({ categories }) => (
  <section className="py-6 md:py-10 bg-white">
    <div className="container mx-auto px-4">
      <h2 className="text-xl md:text-2xl font-bold text-gray-900 mb-4 md:mb-6">
        Shop by Category
      </h2>
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-3 md:gap-4">
        {categories.map((cat) => (
          <Link
            to={`/category/${cat.slug}`}
            key={cat.id}
            className="group block"
          >
            <div className="relative aspect-square rounded-xl overflow-hidden bg-gray-100 shadow-sm hover:shadow-md transition-shadow">
              <img
                src={cat.image}
                alt={cat.name}
                className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                loading="lazy"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent" />
              <span className="absolute bottom-3 left-3 text-white font-semibold text-sm md:text-base">
                {cat.name}
              </span>
            </div>
          </Link>
        ))}
      </div>
    </div>
  </section>
);

export default CategoryGrid;
